import React from 'react';

const UserDetail = () => {
    const {id} = useParams();
    const [user, setUser] = useState({});

    useEffect(() => {
        fetch(`https://jsonplaceholder.typicode.com/users/${id}`)
            .then(response => response.json())
            .then(data => setUser(data))
    }, [id]);

    return (
        <div>
            
        </div>
    );
}

export default UserDetail;
